/*
 * IoT Device Firmware - Microcontroller (MCU) Implementation
 * Platform: ESP32/Arduino compatible
 * Demonstrates: GPIO, I2C sensors, interrupt handling, actuation
 */

#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>
#include "driver/gpio.h"
#include "driver/adc.h"

// ============ CONSTANTS AND DEFINITIONS ============
#define TEMP_SENSOR_PIN     34      // ADC pin for temperature sensor
#define MOTION_SENSOR_PIN   4       // GPIO for PIR motion sensor
#define LED_ACTUATOR_PIN    2       // GPIO for LED output
#define BUZZER_ACTUATOR_PIN 5       // GPIO for buzzer output
#define RELAY_ACTUATOR_PIN  18      // GPIO for relay control

#define TEMP_THRESHOLD      30.0    // Temperature alert threshold (°C)
#define BATTERY_LOW_LIMIT  20      // Battery percentage

// Device state structure (represents device memory)
typedef struct {
    float temperature;
    float humidity;
    bool motion_detected;
    uint8_t battery_level;
    bool led_state;
    bool buzzer_state;
    bool relay_state;
    uint32_t data_packet_count;
} IoTDeviceState;

// Global device state
static IoTDeviceState device_state = {
    .temperature = 0.0,
    .humidity = 0.0,
    .motion_detected = false,
    .battery_level = 100,
    .led_state = false,
    .buzzer_state = false,
    .relay_state = false,
    .data_packet_count = 0
};

// ============ HARDWARE INITIALIZATION ============

/*
 * Initialize GPIO pins for sensors and actuators
 * Core Component: I/O Interfaces (GPIO configuration)
 */
void gpio_init(void) {
    // Configure Motion Sensor Pin as Input
    gpio_pad_select_gpio(MOTION_SENSOR_PIN);
    gpio_set_direction(MOTION_SENSOR_PIN, GPIO_MODE_INPUT);

    // Configure LED as Output (Actuator)
    gpio_pad_select_gpio(LED_ACTUATOR_PIN);
    gpio_set_direction(LED_ACTUATOR_PIN, GPIO_MODE_OUTPUT);

    // Configure Buzzer as Output (Actuator)
    gpio_pad_select_gpio(BUZZER_ACTUATOR_PIN);
    gpio_set_direction(BUZZER_ACTUATOR_PIN, GPIO_MODE_OUTPUT);

    // Configure Relay as Output (Actuator)
    gpio_pad_select_gpio(RELAY_ACTUATOR_PIN);
    gpio_set_direction(RELAY_ACTUATOR_PIN, GPIO_MODE_OUTPUT);

    // Initialize ADC for temperature sensor
    adc1_config_width(ADC_WIDTH_BIT_12);
    adc1_config_channel_atten(TEMP_SENSOR_PIN, ADC_ATTEN_DB_11);

    printf("GPIO pins initialized successfully\n");
}

// ============ SENSOR READING FUNCTIONS ============

/*
 * Read temperature from analog sensor
 * Core Component: Sensors (input devices)
 */
float read_temperature_sensor(void) {
    // Read ADC value (0-4095 for 12-bit ADC)
    int adc_value = adc1_get_raw(TEMP_SENSOR_PIN);

    // Convert ADC to temperature (thermistor approximation)
    // Vout = ADC/4095 * 3.3V, then convert to temperature
    float voltage = (adc_value / 4095.0) * 3.3;
    float temperature = (voltage - 0.5) * 100;  // LM35 style sensor

    return temperature;
}

/*
 * Read motion sensor (PIR)
 * Returns true if motion detected
 */
bool read_motion_sensor(void) {
    int motion_value = gpio_get_level(MOTION_SENSOR_PIN);
    return (motion_value == 1);
}

/*
 * Simulate humidity sensor reading (would use I2C in real hardware)
 * Core Component: I2C interface for peripherals
 */
float read_humidity_sensor(void) {
    // In real implementation, would use I2C protocol
    // This simulates DHT11/DHT22 style sensor
    static float humidity = 50.0;
    humidity += (rand() % 10 - 5) * 0.5;  // Random variation
    if (humidity < 20) humidity = 20;
    if (humidity > 90) humidity = 90;
    return humidity;
}

// ============ ACTUATOR CONTROL FUNCTIONS ============

/*
 * Control LED actuator
 * Core Component: Actuators (output devices)
 */
void set_led_state(bool state) {
    gpio_set_level(LED_ACTUATOR_PIN, state ? 1 : 0);
    device_state.led_state = state;
}

/*
 * Control buzzer actuator (audio feedback)
 */
void set_buzzer_state(bool state) {
    gpio_set_level(BUZZER_ACTUATOR_PIN, state ? 1 : 0);
    device_state.buzzer_state = state;
}

/*
 * Control relay actuator (to switch high-power devices)
 */
void set_relay_state(bool state) {
    gpio_set_level(RELAY_ACTUATOR_PIN, state ? 1 : 0);
    device_state.relay_state = state;
}

// ============ DATA PROCESSING ============

/*
 * Process sensor data and make decisions
 * Core Component: Microcontroller (processing unit)
 */
void process_sensor_data(void) {
    // Update device state with sensor readings
    device_state.temperature = read_temperature_sensor();
    device_state.humidity = read_humidity_sensor();
    device_state.motion_detected = read_motion_sensor();

    // Decision logic: Temperature-based actuation
    if (device_state.temperature > TEMP_THRESHOLD) {
        // Turn on cooling indicator
        set_led_state(true);
        printf("ALERT: High temperature detected! Activating LED\n");
    } else {
        set_led_state(false);
    }

    // Decision logic: Motion-based actuation
    if (device_state.motion_detected) {
        set_buzzer_state(true);
        printf("ALERT: Motion detected! Buzzer activated\n");
    } else {
        set_buzzer_state(false);
    }

    // Decrement battery (simulated power consumption)
    device_state.battery_level -= 1;
    device_state.data_packet_count++;
}

// ============ POWER MANAGEMENT ============

/*
 * Power management function
 * Core Component: Power Supply considerations
 */
void check_power_management(void) {
    if (device_state.battery_level < BATTERY_LOW_LIMIT) {
        printf("WARNING: Low battery (%d%%)\n", device_state.battery_level);
        // In deep sleep, most peripherals would be disabled
        // Only RTC and wake-up sources remain active
    }
}

// ============ MAIN APPLICATION LOOP ============

/*
 * Main IoT device application loop
 * Demonstrates the continuous operation of an IoT device
 */
void app_main(void) {
    printf("\n");
    printf("========================================\n");
    printf("  IoT Device Firmware Started\n");
    printf("  MCU: ESP32 Embedded System\n");
    printf("========================================\n\n");

    // Initialize hardware
    gpio_init();

    // Main control loop (runs continuously)
    int loop_count = 0;
    while (loop_count < 3) {
        printf("\n--- Cycle %d ---\n", loop_count + 1);

        // Step 1: Read sensors (sensing phase)
        printf("Reading sensors...\n");
        float temp = read_temperature_sensor();
        float hum = read_humidity_sensor();
        bool motion = read_motion_sensor();

        printf("  Temperature: %.2f C\n", temp);
        printf("  Humidity: %.2f %%\n", hum);
        printf("  Motion: %s\n", motion ? "DETECTED" : "None");

        // Step 2: Process and make decisions
        printf("Processing data...\n");
        process_sensor_data();

        // Step 3: Power management
        check_power_management();

        // In real application: transmit data to cloud here
        printf("Data packet #%u ready for transmission\n", 
               device_state.data_packet_count);

        // Simulate delay between readings
        // In real hardware: use vTaskDelay() or sleep mode
        for (volatile int i = 0; i < 1000000; i++);

        loop_count++;
    }

    printf("\n========================================\n");
    printf("  IoT Device Firmware Demo Complete\n");
    printf("========================================\n");
}
